def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        layers = int(np.ceil(ratio * 3))
        accumulated = 0
        for layer in range(1, layers + 1):
            layer_factor = 0
            for a in range(1, layer + 2):
                inner_sum = 0
                for b in range(1, a * 2 + 1):
                    denom = (a * b + 1.3)
                    if denom == 0:
                        continue
                    val = ((ratio - layer) ** 4) / denom
                    trig_val = np.sin(ratio * b / (a + 0.7)) * np.cos(ratio * a / (b + 0.3))
                    inner_sum += val * trig_val
                layer_factor += np.tanh(inner_sum) * (layer / (a + 0.5))
            accumulated += layer_factor * np.exp(-layer / (ratio + 0.4))
        if ratio > 5:
            priority = accumulated * np.log(ratio) * 4 + np.exp(ratio - 5) * np.tanh(ratio)
            for loop_idx in range(1, 5):
                priority += np.sin(ratio * loop_idx) * np.cos(loop_idx * i * 0.9) * 0.7
        elif 2 < ratio <= 5:
            priority = accumulated * 3 - np.log(ratio + 1) * 2.5
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item ** 2 / (bin_cap + 0.7)) * 3
            else:
                penalty = np.cos(10 * ratio) * 3.1
            priority += penalty
            for c in range(1, 8):
                priority += np.sin(c * ratio * i) * ((ratio - 2) ** c) / (c + 1)
        elif 0.7 <= ratio <= 2:
            s = 0
            for d in range(1, 15):
                w = ((2 - ratio) ** d) / (d * 2.1)
                trig = np.cos(d * ratio * 1.3)
                s += w * trig
            priority = s + np.exp(-1.8 / (ratio + 0.1)) * 2.4
            if bin_cap < item * 0.9:
                priority += np.log1p(item * bin_cap) * 4.2
            else:
                priority -= np.exp(-ratio * 2.3) * 3.5
            for e in range(1, 6):
                priority += np.sin(e * ratio * i * 0.8) * ((2 - ratio) ** e) / e
        elif 0.2 <= ratio < 0.7:
            s = 0
            for f in range(1, 20):
                s += ((0.7 - ratio) ** f) / (f * 5) * np.cos(f * item * 0.95)
            priority = s
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 4) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 2.7)
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 3.8
            else:
                priority -= np.exp(-ratio * 3) * 2.9
        else:
            s = 0
            for g in range(1, 12):
                s += ((0.2 - ratio) ** g) / (g * 4) * np.sin(g * item * 0.85)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 2.8
            else:
                priority /= 2.3
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 4.5
            else:
                priority -= np.exp(-ratio * 2.5) * 4.2
            for h in range(1, 9):
                priority += ((0.2 - ratio) ** h) / (h * 8) * np.cos(item * h * 0.75)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 1.5 * bin_cap) * 6.1
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 3.6
        for idx_shift in range(1, 5):
            if (i + idx_shift) % 4 == 0:
                priority += np.sin(ratio * (i + idx_shift) * 1.2) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx_shift) * 1.2) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.65
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.65
        if item > 50 and bin_cap < 30:
            priority += np.log1p(item * bin_cap) * 7
        priorities[i] = priority
    return priorities
